            VOL_UP:   '807',  VOL_DOWN: '808',  MUTE:     '809',
            CH_UP:    '1308',  CH_DOWN:  '1307',
            DPAD_UP:  '544',   DPAD_DOWN:'545',   DPAD_LEFT:'546',
            DPAD_RIGHT:'547',  DPAD_OK:  '548',
            KEY_0: '558', KEY_1: '549', KEY_2: '550', KEY_3: '551',
