        POWER_FB:      '',  // D <- current power state
        MODE_AUTO:     '',  MODE_AUTO_FB:     '',
        MODE_COOL:     '',  MODE_COOL_FB:     '',
        MODE_HEAT:     '',  MODE_HEAT_FB:     '',
        MODE_DRY:      '',  MODE_DRY_FB:      '',
